import { Component } from '@angular/core';

 // Definição correta do tipo fora da classe
 type AtributoNome = 'forca' | 'destreza' | 'constituicao' | 'inteligencia' | 'sabedoria' | 'carisma';

@Component({
  selector: 'app-criar-personagem',
  templateUrl: './criar-personagem.component.html',
  styleUrls: ['./criar-personagem.component.css']
})
export class CriarPersonagemComponent {
  etapa: number = 1;
  metodoAtributos: 'rolagem' | 'manual' | null = null;

  racas = [
    { nome: 'Humano', img: undefined },
    { nome: 'Elfo', img: undefined },
    { nome: 'Anão', img: undefined },
    { nome: 'Halfling', img: undefined },
    { nome: 'Gnomo', img: undefined },
    { nome: 'Meio-Orc', img: undefined },
    { nome: 'Meio-Elfo', img: undefined },
    { nome: 'Draconato', img: undefined },
    { nome: 'Tiefling', img: undefined }
  ];

  classes = [
    { nome: 'Bárbaro', img: undefined },
    { nome: 'Bardo', img: undefined },
    { nome: 'Bruxo', img: undefined },
    { nome: 'Clérigo', img: undefined },
    { nome: 'Druida', img: undefined },
    { nome: 'Feiticeiro', img: undefined },
    { nome: 'Guerreiro', img: undefined },
    { nome: 'Ladino', img: undefined },
    { nome: 'Mago', img: undefined },
    { nome: 'Monge', img: undefined },
    { nome: 'Paladino', img: undefined },
    { nome: 'Patrulheiro', img: undefined }
  ];

  personagem = {
    raca: '',
    classe: '',
    atributos: {
      forca: 0,
      destreza: 0,
      constituicao: 0,
      inteligencia: 0,
      sabedoria: 0,
      carisma: 0
    }
  };


  selecionarRaca(raca: string) {
    this.personagem.raca = raca;
    this.etapa = 2;
  }

  selecionarClasse(classe: string) {
    this.personagem.classe = classe;
    this.etapa = 3;
  }

  escolherMetodoAtributos(metodo: 'rolagem' | 'manual') {
    this.metodoAtributos = metodo;
    if (metodo === 'rolagem') {
      this.rolarAtributos();
    }
    this.etapa = 4;
  }

  definirAtributo(atributo: AtributoNome, valor: number) {
    this.personagem.atributos[atributo] = valor;
  }

  rolarAtributos() {
    for (const atributo of Object.keys(this.personagem.atributos) as AtributoNome[]) {
      this.personagem.atributos[atributo] = this.rolarDado();
    }
  }

  rolarDado(): number {
    let rolagens = [
      Math.floor(Math.random() * 6) + 1,
      Math.floor(Math.random() * 6) + 1,
      Math.floor(Math.random() * 6) + 1,
      Math.floor(Math.random() * 6) + 1
    ];
    rolagens.sort((a, b) => a - b).shift(); // Remove o menor valor
    return rolagens.reduce((a, b) => a + b, 0);
  }

  voltarEtapa() {
    if (this.etapa! > 1) { // Adicionando "!" para evitar erro de undefined
      if (this.etapa! === 4) {
        this.metodoAtributos = null;
      }
      this.etapa!--;
    }
  }
}
